#!/usr/bin/env python3
import os,sys,json,glob,time,subprocess,base64,urllib.request,urllib.error,re
def load_env():
    for p in ("/etc/atlas/autopull.env","/etc/atlas/db.env"):
        if os.path.exists(p):
            for ln in open(p):
                ln=ln.strip()
                if ln.startswith("export "): ln=ln[7:]
                if "=" in ln and not ln.startswith("#"):
                    k,v=ln.split("=",1); k=k.strip()
                    if k and k not in os.environ: os.environ[k]=v.strip().strip('"').strip("'")
load_env()
o={"kind":"srchunt-diag2","ts":int(time.time())}
cands=[]
for pat in ("*hunter*","*source*","*discover*","*socrata*","*promote*","*geo*","*reenrich*","*requeue*","*qa*"):
    cands+=glob.glob("/opt/atlas/**/"+pat+".py",recursive=True)
o["scripts"]=[{"path":f,"bytes":os.path.getsize(f)} for f in sorted(set(cands))[:30]]
# source-hunter head (the main discovery script)
for f in sorted(set(cands)):
    if "hunter" in f.lower() or "source" in f.lower() or "promote" in f.lower():
        try: o.setdefault("hunter_heads",{})[f]=open(f,encoding="utf-8",errors="replace").read()[:2000]
        except Exception as e: o.setdefault("hunter_heads",{})[f]="ERR"+str(e)
        if len(o.get("hunter_heads",{}))>=3: break
try:
    u=subprocess.run(["bash","-lc","systemctl list-units --type=service,timer --all --no-pager 2>/dev/null | grep -iE 'atlas|source|hunter|socrata|deepcrawl|reenrich' | awk '{print $1,$3,$4}'"],capture_output=True,text=True).stdout
    o["units"]=u[:2500]
except Exception as e: o["units"]="ERR"+str(e)
try:
    sys.path.insert(0,"/opt/atlas/importers"); import socrata_import as si
    c=si.connect_pg(); cur=c.cursor()
    cur.execute("SELECT count(distinct source) FROM atlas.business"); o["source_count"]=int(cur.fetchone()[0])
    cur.execute("SELECT source,count(*) FROM atlas.business GROUP BY 1 ORDER BY 2 DESC LIMIT 30"); o["source_dist"]=[[r[0],int(r[1])] for r in cur.fetchall()]
    cur.execute("SELECT region,count(*) FROM atlas.business WHERE region IS NOT NULL GROUP BY 1 ORDER BY 2 DESC LIMIT 25"); o["region_dist"]=[[r[0],int(r[1])] for r in cur.fetchall()]
    # ICP industry composition (category)
    try:
        cur.execute("SELECT lower(category),count(*) FROM atlas.business WHERE category IS NOT NULL GROUP BY 1 ORDER BY 2 DESC LIMIT 40"); o["category_dist"]=[[r[0],int(r[1])] for r in cur.fetchall()]
    except Exception as e: o["category_dist"]="ERR"+str(e)
    cur.execute("SELECT count(*) FROM atlas.business WHERE email IS NOT NULL AND email<>''"); o["with_email"]=int(cur.fetchone()[0])
    cur.execute("SELECT count(*) FROM atlas.business WHERE website IS NOT NULL"); o["with_website"]=int(cur.fetchone()[0])
    c.close()
except Exception as e: o["db_err"]=str(e)[:300]
# autopull push fn + qa gate
try: o["autopull_push"]=re.search(r'(gh_put|status.?push|409)[\s\S]{0,900}',open(glob.glob("/opt/atlas/**/atlas-autopull.sh",recursive=True)[0]).read()).group(0)[:1100]
except Exception as e: o["autopull_push"]="ERR"+str(e)
def put(obj):
    tok=os.environ.get("STATUS_TOKEN");repo=os.environ.get("STATUS_REPO","cloudwalker171/atlas-manifests")
    url="https://api.github.com/repos/%s/contents/status/hetzner/srchunt-diag2.json"%repo
    for _ in range(6):
        sha=None
        try:
            rr=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"User-Agent":"atlas","Accept":"application/vnd.github+json"})
            sha=json.load(urllib.request.urlopen(rr,timeout=20)).get("sha")
        except Exception: sha=None
        b={"message":"diag2","content":base64.b64encode(json.dumps(obj,indent=1,default=str).encode()).decode(),"branch":"main"}
        if sha:b["sha"]=sha
        try:
            rq=urllib.request.Request(url,data=json.dumps(b).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"User-Agent":"atlas","Content-Type":"application/json","Accept":"application/vnd.github+json"})
            urllib.request.urlopen(rq,timeout=25); print("diag2 ok"); return
        except urllib.error.HTTPError as e:
            if e.code==409: time.sleep(1.5); continue
            print("err",e.code); return
        except Exception as e: print("err",str(e)[:80]); return
    print("err 409 retries")
put(o)
